To resolve the issues with the voice chat (Thomas not answering, potential connection drops, and permission/argument errors), I have performed a comprehensive overhaul of the `ChatSessionPage.tsx` component.

**Key Improvements:**

1.  **Robust Connection Handling**: I implemented a "Deferred Promise" pattern for the Live API session. This eliminates a potential "Temporal Dead Zone" race condition where the `onopen` callback might try to access the session variable before it was fully initialized.
2.  **Audio Visualizer & Volume Meter**: I added a real-time volume meter. This is crucial for feedback—if the ring around the avatar pulses when you speak, the microphone is working. If it stays flat, the issue is hardware/permissions.
3.  **Safe Audio Context Management**: Explicit `resume()` calls were added for AudioContexts to satisfy browser autoplay policies, ensuring audio isn't blocked silently.
4.  **Simplified Configuration**: I kept the transcription configuration minimal (`{}`) to avoid "Invalid Argument" errors while ensuring you still get text transcripts of the voice conversation.
5.  **Clearer Error Feedback**: Enhanced error messages for microphone permissions and connection failures.

These changes should ensure Thomas (and other patients) can hear you and respond reliably.

# Updated files:

## pages/ChatSessionPage.tsx

```tsx
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Chat, LiveServerMessage, Modality } from '@google/genai';

import { useLanguage } from '../contexts/LanguageContext';
import {
  PredefinedSessionData,
  CustomSessionData,
  TranscriptionLine,
  EmotionalState,
  SessionAnalyticsData,
  Gender,
} from '../types';
import { patients } from '../constants';
import {
  ai,
  getSystemInstructionForScenario,
  getSessionAnalytics,
} from '../services/geminiService';
import { downloadTranscript, saveSession } from '../services/sessionService';

import LoadingScreen from '../components/LoadingScreen';
import PatientInfoSidebar from '../components/PatientInfoSidebar';
import EndSessionModal from '../components/EndSessionModal';
import ConfirmationModal from '../components/ConfirmationModal';
import SessionAnalyticsModal from '../components/SessionAnalyticsModal';
import EmotionalStateIndicator from '../components/EmotionalStateIndicator';

// Icons
import SendIcon from '../components/icons/SendIcon';
import InfoIcon from '../components/icons/InfoIcon';
import LightbulbIcon from '../components/icons/LightbulbIcon';
import PhoneIcon from '../components/icons/PhoneIcon';
import ChatBubbleLeftEllipsisIcon from '../components/icons/ChatBubbleLeftEllipsisIcon';
import MicrophoneIcon from '../components/icons/MicrophoneIcon';
import StopIcon from '../components/icons/StopIcon';
import SpeakerWaveIcon from '../components/icons/SpeakerWaveIcon';

// --- Audio Utils for Live API ---

function downsampleBuffer(buffer: Float32Array, inputSampleRate: number, targetSampleRate: number): Int16Array {
  if (inputSampleRate === targetSampleRate) {
    const l = buffer.length;
    const res = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      res[i] = Math.max(-32768, Math.min(32767, buffer[i] * 32768));
    }
    return res;
  }

  const sampleRateRatio = inputSampleRate / targetSampleRate;
  const newLength = Math.round(buffer.length / sampleRateRatio);
  const result = new Int16Array(newLength);
  let offsetResult = 0;
  let offsetBuffer = 0;

  while (offsetResult < result.length) {
    const nextOffsetBuffer = Math.round((offsetResult + 1) * sampleRateRatio);
    let accum = 0, count = 0;
    for (let i = offsetBuffer; i < nextOffsetBuffer && i < buffer.length; i++) {
      accum += buffer[i];
      count++;
    }
    const avg = count > 0 ? accum / count : 0;
    result[offsetResult] = Math.max(-32768, Math.min(32767, avg * 32768));
    offsetResult++;
    offsetBuffer = nextOffsetBuffer;
  }
  return result;
}

function arrayBufferToBase64(buffer: ArrayBuffer) {
    let binary = '';
    const bytes = new Uint8Array(buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
}

function base64ToFloat32Array(base64: string): Float32Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  const int16Data = new Int16Array(bytes.buffer);
  const float32Data = new Float32Array(int16Data.length);
  for (let i = 0; i < int16Data.length; i++) {
    float32Data[i] = int16Data[i] / 32768.0;
  }
  return float32Data;
}

// --- Component Logic ---

const emotionalStateRegex = /\[EMOTIONAL_STATE:\s*(\w+)\s*\]/;

const parseEmotionalState = (text: string): EmotionalState | null => {
    const match = text.match(emotionalStateRegex);
    if (match && match[1]) {
        return match[1] as EmotionalState;
    }
    return null;
}

const cleanTextOfTags = (text: string): string => {
    return text.replace(emotionalStateRegex, '').trim();
}

interface ChatSessionPageProps {
  sessionData: PredefinedSessionData | CustomSessionData;
  onEndSession: () => void;
}

const ChatSessionPage: React.FC<ChatSessionPageProps> = ({ sessionData, onEndSession }) => {
  const { t } = useLanguage();

  // Component State
  const [isLoading, setIsLoading] = useState(true);
  const [isModelResponding, setIsModelResponding] = useState(false);
  const [userInput, setUserInput] = useState('');
  const [error, setError] = useState<string | null>(null);

  // Voice Mode State
  const [isVoiceMode, setIsVoiceMode] = useState(false);
  const [isLiveConnected, setIsLiveConnected] = useState(false);
  const [isMicActive, setIsMicActive] = useState(false);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [volumeLevel, setVolumeLevel] = useState(0);

  // Transcript and Session State
  const [messages, setMessages] = useState<TranscriptionLine[]>([]);
  const [currentEmotionalState, setCurrentEmotionalState] = useState<EmotionalState | null>(null);
  const chatHistoryEndRef = useRef<HTMLDivElement>(null);

  // Modals
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isEndSessionModalOpen, setIsEndSessionModalOpen] = useState(false);
  const [isFeedbackConfirmOpen, setIsFeedbackConfirmOpen] = useState(false);
  const [isAnalyticsOpen, setIsAnalyticsOpen] = useState(false);
  const [analyticsData, setAnalyticsData] = useState<SessionAnalyticsData | null>(null);
  const [isFeedbackLoading, setIsFeedbackLoading] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);

  // Refs for APIs and instances
  const textChatRef = useRef<Chat | null>(null);
  const progressIntervalRef = useRef<number | null>(null);

  // Live API Refs
  const liveSessionRef = useRef<any>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const audioStreamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<AudioBufferSourceNode[]>([]);
  const isInterruptingRef = useRef<boolean>(false);
  const volumeIntervalRef = useRef<number | null>(null);

  // Session data extraction
  const patient = sessionData.mode === 'predefined' ? patients.find(p => p.id === sessionData.patientId) : null;
  const systemInstruction = sessionData.mode === 'predefined' ? getSystemInstructionForScenario(sessionData.scenarioId) : sessionData.systemInstruction;
  const patientName = sessionData.mode === 'predefined' && patient ? t(patient.nameKey) : 'Custom Patient';
  const patientAvatarUrl = patient?.avatarUrl || 'https://picsum.photos/seed/custom/100/100';
  const patientGender: Gender = sessionData.mode === 'custom' 
    ? sessionData.config.gender 
    : (patient?.id === 'tomas-perez' ? 'male' : 'female');

  // Determine Voice for Live API
  const voiceName = patient?.voiceName || (patientGender === 'male' ? 'Fenrir' : 'Kore');

  const scrollToBottom = () => {
    chatHistoryEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };
  useEffect(scrollToBottom, [messages]);

  // --- Text Chat Logic ---
  const handleSendMessage = useCallback(async (messageText: string) => {
    if (!messageText.trim() || !textChatRef.current) return;

    const newUserMessage: TranscriptionLine = { speaker: 'user', text: messageText, timestamp: Date.now() };
    const newModelMessagePlaceholder: TranscriptionLine = { speaker: 'model', text: '', timestamp: Date.now() };

    setMessages(prev => [...prev, newUserMessage, newModelMessagePlaceholder]);
    setIsModelResponding(true);
    setUserInput('');

    try {
        const stream = await textChatRef.current.sendMessageStream({ message: messageText });

        let fullModelText = '';
        for await (const chunk of stream) {
            const chunkText = chunk.text;
            if (chunkText) {
                fullModelText += chunkText;
                const newState = parseEmotionalState(fullModelText);
                if (newState) {
                    setCurrentEmotionalState(newState);
                }

                setMessages(prev => {
                    const updatedMessages = [...prev];
                    const lastMessage = updatedMessages[updatedMessages.length - 1];
                    if (lastMessage && lastMessage.speaker === 'model') {
                        lastMessage.text = cleanTextOfTags(fullModelText);
                    }
                    return updatedMessages;
                });
            }
        }
    } catch (err) {
        console.error("Error sending message:", err);
        setError(t('chat.error.send'));
        setMessages(prev => prev.slice(0, -1)); // Remove placeholder on error
    } finally {
        setIsModelResponding(false);
    }
  }, [t]);

  // --- Live API Logic ---

  const stopLiveSession = () => {
    if (volumeIntervalRef.current) clearInterval(volumeIntervalRef.current);
    setVolumeLevel(0);

    if (liveSessionRef.current) {
        try {
            liveSessionRef.current.close();
        } catch (e) { console.error("Error closing session", e); }
        liveSessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current.onaudioprocess = null;
        scriptProcessorRef.current = null;
    }
    if (audioStreamRef.current) {
        audioStreamRef.current.getTracks().forEach(track => track.stop());
        audioStreamRef.current = null;
    }
    if (inputAudioContextRef.current) {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
        outputAudioContextRef.current.close();
        outputAudioContextRef.current = null;
    }
    setIsLiveConnected(false);
    setIsMicActive(false);
    setIsPlayingAudio(false);
    isInterruptingRef.current = false;
  };

  const startLiveSession = async () => {
    setError(null);
    // Ensure clean state
    stopLiveSession(); 

    try {
        // 1. Request Microphone Permission FIRST
        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
             throw new Error("Audio recording is not supported in this browser.");
        }

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        audioStreamRef.current = stream;

        // 2. Initialize Audio Contexts
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        inputAudioContextRef.current = new AudioContextClass(); 
        outputAudioContextRef.current = new AudioContextClass();

        // Resume contexts immediately (good practice for some browsers)
        if (inputAudioContextRef.current.state === 'suspended') await inputAudioContextRef.current.resume();
        if (outputAudioContextRef.current.state === 'suspended') await outputAudioContextRef.current.resume();

        nextStartTimeRef.current = 0;
        audioSourcesRef.current = [];

        // Create a Deferred Promise to avoid TDZ/Initialization race conditions
        let resolveSession: (value: any) => void;
        const sessionPromise = new Promise<any>((resolve) => {
            resolveSession = resolve;
        });

        // 3. Connect to Gemini Live
        const connectPromise = ai.live.connect({
            model: 'gemini-2.5-flash-native-audio-preview-09-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: voiceName } },
                },
                systemInstruction: systemInstruction,
                inputAudioTranscription: {}, 
                outputAudioTranscription: {}, 
            },
            callbacks: {
                onopen: () => {
                    console.log("Live Session Opened");
                    setIsLiveConnected(true);
                    setIsMicActive(true);

                    if (!inputAudioContextRef.current || !stream) return;

                    const source = inputAudioContextRef.current.createMediaStreamSource(stream);
                    const scriptProcessor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
                    scriptProcessorRef.current = scriptProcessor;

                    scriptProcessor.onaudioprocess = (e) => {
                        if (!inputAudioContextRef.current || isInterruptingRef.current) return;

                        const inputData = e.inputBuffer.getChannelData(0);

                        // Volume Visualization Logic
                        let sum = 0;
                        for(let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
                        const rms = Math.sqrt(sum / inputData.length);
                        // Smooth volume update
                        setVolumeLevel(prev => Math.max(0, Math.min(100, prev * 0.8 + rms * 500)));

                        const currentSampleRate = inputAudioContextRef.current.sampleRate;

                        // Downsample to 16kHz
                        const pcm16 = downsampleBuffer(inputData, currentSampleRate, 16000);

                        // Convert to Base64 Synchronously
                        const base64Data = arrayBufferToBase64(pcm16.buffer);

                        // Use the deferred promise to ensure we have the session object
                        sessionPromise.then(session => {
                             try {
                                 session.sendRealtimeInput({
                                     media: {
                                         mimeType: 'audio/pcm;rate=16000',
                                         data: base64Data
                                     }
                                 });
                             } catch (sendError) {
                                 console.error("Error sending audio data:", sendError);
                             }
                        }).catch(err => {
                            console.error("Session promise error", err);
                        });
                    };

                    source.connect(scriptProcessor);
                    scriptProcessor.connect(inputAudioContextRef.current.destination);
                },
                onmessage: async (message: LiveServerMessage) => {
                    // Handle Interruption
                    if (message.serverContent?.interrupted) {
                         isInterruptingRef.current = true;
                         audioSourcesRef.current.forEach(source => {
                             try { source.stop(); } catch(e) {}
                         });
                         audioSourcesRef.current = [];
                         if (outputAudioContextRef.current) {
                             nextStartTimeRef.current = outputAudioContextRef.current.currentTime;
                         }
                         setIsPlayingAudio(false);
                         setTimeout(() => { isInterruptingRef.current = false; }, 500);
                         return;
                    }

                    // Handle Output Audio
                    const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (base64Audio && outputAudioContextRef.current && !isInterruptingRef.current) {
                        setIsPlayingAudio(true);
                        const float32Data = base64ToFloat32Array(base64Audio);
                        const buffer = outputAudioContextRef.current.createBuffer(1, float32Data.length, 24000);
                        buffer.getChannelData(0).set(float32Data);

                        const source = outputAudioContextRef.current.createBufferSource();
                        source.buffer = buffer;
                        source.connect(outputAudioContextRef.current.destination);

                        const startTime = Math.max(outputAudioContextRef.current.currentTime, nextStartTimeRef.current);
                        source.start(startTime);
                        nextStartTimeRef.current = startTime + buffer.duration;

                        audioSourcesRef.current.push(source);

                        source.onended = () => {
                            audioSourcesRef.current = audioSourcesRef.current.filter(s => s !== source);
                            if (audioSourcesRef.current.length === 0) {
                                setIsPlayingAudio(false);
                            }
                        };
                    }

                    // Handle Transcription
                    const isUserTurn = !!message.serverContent?.inputTranscription;
                    const transcriptionText = message.serverContent?.inputTranscription?.text || message.serverContent?.outputTranscription?.text;

                    if (transcriptionText) {
                        setMessages(prev => {
                            const updated = [...prev];
                            const lastMsg = updated[updated.length - 1];
                            const speaker = isUserTurn ? 'user' : 'model';

                            if (lastMsg && lastMsg.speaker === speaker) {
                                lastMsg.text += transcriptionText;
                            } else {
                                updated.push({
                                    speaker: speaker,
                                    text: transcriptionText,
                                    timestamp: Date.now()
                                });
                            }

                            if (!isUserTurn) {
                                const newState = parseEmotionalState(transcriptionText);
                                if (newState) setCurrentEmotionalState(newState);
                            }

                            if(lastMsg && lastMsg.speaker === 'model') {
                                lastMsg.text = cleanTextOfTags(lastMsg.text);
                            }

                            return updated;
                        });
                    }
                },
                onclose: () => {
                    console.log("Live Session Closed");
                    setIsLiveConnected(false);
                    setIsMicActive(false);
                },
                onerror: (e) => {
                    console.error("Live Session Error Event:", e);
                    setError("Connection error: " + (e instanceof Error ? e.message : "Unknown error. Please try refreshing."));
                    stopLiveSession();
                }
            }
        });

        // Resolve the session promise once the connection object is available
        connectPromise.then(session => {
            liveSessionRef.current = session;
            resolveSession(session);
        }).catch(err => {
             console.error("Connect promise failed", err);
             setError("Failed to connect to AI service.");
             stopLiveSession();
        });

    } catch (err: any) {
        console.error("Start live session exception:", err);
        let errorMessage = t('chat.error.start');

        if (err.name === 'NotAllowedError' || err.message.includes('Permission denied') || err.message.includes('permission')) {
            errorMessage = "Microphone access denied. Please enable microphone permissions in your browser settings.";
        } else if (err.name === 'NotFoundError' || err.message.includes('device')) {
            errorMessage = "No microphone found. Please ensure your microphone is connected.";
        } else if (err.message.includes('Supported')) {
            errorMessage = err.message;
        } else if (err.message.includes('invalid argument')) {
            errorMessage = "Configuration error: Invalid arguments sent to API.";
        }

        setError(errorMessage);
        stopLiveSession();
        setIsVoiceMode(false);
    }
  };

  const toggleMic = async () => {
      if (!inputAudioContextRef.current) return;
      if (inputAudioContextRef.current.state === 'suspended') {
          await inputAudioContextRef.current.resume();
          setIsMicActive(true);
      } else if (inputAudioContextRef.current.state === 'running') {
          await inputAudioContextRef.current.suspend();
          setIsMicActive(false);
          setVolumeLevel(0);
      }
  }

  const toggleVoiceMode = () => {
      if (isVoiceMode) {
          // Switch to Text
          stopLiveSession();
          textChatRef.current = ai.chats.create({
              model: 'gemini-2.5-flash',
              config: { systemInstruction: systemInstruction },
          });
      } else {
          // Switch to Voice
          startLiveSession();
      }
      setIsVoiceMode(!isVoiceMode);
  };

  // Setup on Mount
  useEffect(() => {
    // Default to text mode init
    textChatRef.current = ai.chats.create({
        model: 'gemini-2.5-flash',
        config: { systemInstruction: systemInstruction },
    });
    setIsLoading(false);

    return () => {
      if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
      stopLiveSession();
    }
  }, [systemInstruction]);

  // Analytics Generation
  const handleGetFeedback = async () => {
    setIsFeedbackConfirmOpen(false);
    setIsFeedbackLoading(true);
    setLoadingProgress(0);

    progressIntervalRef.current = window.setInterval(() => {
        setLoadingProgress(prev => {
            if (prev >= 95) {
                if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
                return 95;
            }
            return prev + Math.floor(Math.random() * 5) + 1;
        });
    }, 500);

    try {
        const data = await getSessionAnalytics(messages, systemInstruction);
        if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
        setLoadingProgress(100);
        setAnalyticsData(data);
        if (data) {
            setIsAnalyticsOpen(true);
        } else {
            setError(t('chat.error.feedback'));
        }
    } catch(err) {
        console.error("Error getting analytics:", err);
        setError(t('chat.error.feedback'));
        if (progressIntervalRef.current) clearInterval(progressIntervalRef.current);
    } finally {
        setTimeout(() => setIsFeedbackLoading(false), 500);
    }
  };

  const handleDownloadAndEnd = () => {
    downloadTranscript(messages, patientName);
    onEndSession();
  };

  const handleSaveAndEnd = () => {
    saveSession(messages, patientName).then(() => {
      onEndSession();
    });
  };

  if (isLoading) return <LoadingScreen />;

  return (
    <div className="h-screen w-screen bg-background-light flex font-sans overflow-hidden">
      <PatientInfoSidebar
        patientId={sessionData.mode === 'predefined' ? sessionData.patientId : undefined}
        customConfig={sessionData.mode === 'custom' ? sessionData.config : undefined}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />
      <div className="flex-1 flex flex-col h-full relative">
        <header className="bg-white border-b border-gray-200 p-4 flex justify-between items-center shrink-0 shadow-sm z-10">
          <div className="flex items-center space-x-3">
            <div className="relative">
                <img src={patientAvatarUrl} alt={patientName} className="w-12 h-12 rounded-full border-2 border-white shadow-sm" />
                {isVoiceMode && isLiveConnected && (
                    <div className="absolute -bottom-1 -right-1 bg-green-500 w-4 h-4 rounded-full border-2 border-white animate-pulse"></div>
                )}
            </div>
            <div>
              <div className="flex items-center space-x-3">
                 <h2 className="text-lg font-bold text-primary-dark">{patientName}</h2>
                 {!isVoiceMode && <EmotionalStateIndicator state={currentEmotionalState} gender={patientGender} />}
              </div>
              <p className="text-sm text-gray-500 h-5 flex items-center">
                 {isModelResponding || isPlayingAudio ? (
                    <span className="animate-pulse text-accent font-medium">{t(patientName.startsWith("Tomás") ? 'chat.loadingTomas' : 'chat.loadingAntonia')}</span>
                 ) : (
                    <span>{isVoiceMode ? 'Listening...' : t(patientName.startsWith("Tomás") ? 'chat.headerTomas' : 'chat.headerAntonia')}</span>
                 )}
              </p>
            </div>
          </div>
          <div className="flex items-center space-x-2">
             <button 
                onClick={toggleVoiceMode}
                className={`flex items-center space-x-2 px-3 py-2 rounded-lg transition-all duration-300 border ${isVoiceMode ? 'bg-primary-dark text-white border-primary-dark' : 'bg-white text-primary-dark border-gray-300 hover:bg-gray-50'}`}
                title={isVoiceMode ? "Switch to Text" : "Switch to Voice"}
            >
                {isVoiceMode ? <ChatBubbleLeftEllipsisIcon className="w-5 h-5" /> : <PhoneIcon className="w-5 h-5" />}
                <span className="hidden md:inline text-sm font-semibold">{isVoiceMode ? 'Text Mode' : 'Voice Mode'}</span>
            </button>

            <div className="h-6 w-px bg-gray-300 mx-2"></div>

            <button onClick={() => setIsFeedbackConfirmOpen(true)} className="flex items-center space-x-2 text-sm font-semibold bg-yellow-100 text-yellow-800 px-3 py-2 rounded-lg hover:bg-yellow-200 transition disabled:opacity-50 disabled:cursor-not-allowed" disabled={messages.length === 0}>
              <LightbulbIcon className="w-5 h-5"/>
              <span className="hidden md:inline">{t('chat.getFeedback')}</span>
            </button>
            <button onClick={() => setIsEndSessionModalOpen(true)} className="text-sm font-semibold bg-red-100 text-red-800 px-3 py-2 rounded-lg hover:bg-red-200 transition">
              <span className="hidden md:inline">{t('chat.endSession')}</span>
              <span className="md:hidden">End</span>
            </button>
            <button onClick={() => setIsSidebarOpen(true)} className="p-2 rounded-full hover:bg-gray-100 lg:hidden">
              <InfoIcon className="w-6 h-6 text-gray-500"/>
            </button>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-6 bg-gray-50 relative">
            {/* Error Toast */}
            {error && (
                <div className="absolute top-4 left-1/2 transform -translate-x-1/2 bg-red-500 text-white px-4 py-2 rounded-full shadow-lg text-sm font-semibold z-20 animate-fade-in-up text-center max-w-lg w-full">
                    {error}
                </div>
            )}

            {isVoiceMode ? (
                <div className="flex flex-col h-full">
                    {/* Live Visualizer Area */}
                    <div className="flex-grow flex flex-col items-center justify-center space-y-8 py-10">
                        <div className="relative">
                            <div className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-200 ${isPlayingAudio ? 'scale-110 shadow-[0_0_50px_rgba(230,126,34,0.6)] bg-accent/10' : 'bg-gray-100'}`}
                                 style={isMicActive && !isPlayingAudio ? { boxShadow: `0 0 ${volumeLevel * 2}px rgba(52, 211, 153, 0.6)` } : {}}
                            >
                                <img src={patientAvatarUrl} alt={patientName} className="w-40 h-40 rounded-full object-cover" />
                            </div>
                            {isPlayingAudio && (
                                <div className="absolute -bottom-8 left-1/2 transform -translate-x-1/2">
                                    <SpeakerWaveIcon className="w-8 h-8 text-accent animate-bounce" />
                                </div>
                            )}
                            {isMicActive && !isPlayingAudio && volumeLevel > 5 && (
                                 <div className="absolute -bottom-8 left-1/2 transform -translate-x-1/2 flex flex-col items-center">
                                    <div className="flex space-x-1 h-4 items-end">
                                        <div className="w-1 bg-green-500 rounded-full animate-pulse" style={{height: `${Math.min(100, volumeLevel)}%`}}></div>
                                        <div className="w-1 bg-green-500 rounded-full animate-pulse delay-75" style={{height: `${Math.min(100, volumeLevel * 0.8)}%`}}></div>
