            if (isLiveSessionActiveRef.current) {
                liveSessionRef.current = session;
                resolveSession(session);
            } else {
                // If session was cancelled during connect, close it immediately
                session.close();
            }
        }).catch(err => {
             console.error("Connect promise failed", err);
             setError("Failed to connect to AI service.");
             stopLiveSession();
        });

    } catch (err: any) {
        console.error("Start live session exception:", err);
        let errorMessage = t('chat.error.start');

        if (err.name === 'NotAllowedError' || err.message.includes('Permission denied') || err.message.includes('permission')) {
